// --- SEO Component to inject JSON-LD ---
const SchemaMarkup: FC<{ schema: any }> = ({ schema }) => {
  useEffect(() => {
    const script = document.createElement('script');
    script.type = 'application/ld+json';
    script.text = JSON.stringify(schema);
    document.head.appendChild(script);
    return () => {
      document.head.removeChild(script);
    };
  }, [schema]);
  return null;
};

// --- UI Components ---
interface SearchBarProps {
  onSearch: (query: string) => void;
  isLoading: boolean;
  query: string;
  setQuery: (q: string) => void;
}
const SearchBar: FC<SearchBarProps> = ({ onSearch, isLoading, query, setQuery }) => {
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim() && !isLoading) {
      onSearch(query.trim());
    }
  };

  return (
    <form onSubmit={handleSubmit} role="search" className="w-full max-w-2xl mx-auto">
      <div className="relative">
        <label htmlFor="organic-search-input" className="sr-only">Search for organic products</label>
        <input
          id="organic-search-input"
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Search for milk, apples, skincare... (Organic is automatic)"
          className="w-full pl-4 pr-12 py-3 border-2 border-organic-green-light focus:border-organic-green-dark focus:ring-organic-green-dark rounded-full shadow-sm transition-colors duration-300"
          disabled={isLoading}
          aria-busy={isLoading}
        />
        <button
          type="submit"
          disabled={isLoading}
          aria-label="Submit Search"
          className="absolute inset-y-0 right-0 flex items-center justify-center w-12 h-full text-white bg-organic-green hover:bg-organic-green-dark rounded-r-full disabled:bg-gray-400"
        >
          {isLoading ? (
            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
          ) : (
            <SearchIcon className="w-6 h-6" />
          )}
        </button>
      </div>
    </form>
  );
};

interface GuideSectionProps {
