      "Fair-trade coffee beans",
      "Sulfate-free shampoo",
      "Local raw honey",
      "Cotton baby clothes",
      "Gluten-free pasta",
      "Dry red wine"
    ];

    const faqs = [
      {
        q: "Do I need to type 'organic'?",
        a: "No. Our search engine automatically filters for certified organic results. Just type 'coffee' or 'soap', and we handle the strict purity checks for you."
      },
      {
        q: "How does Search for Organics work?",
        a: "We use Gemini-powered AI to scan global databases for certified organic products. We analyze ingredients, certifications, and vendor data to prioritize the purest and most sustainable options."
      },
      {
        q: "What certifications do you verify?",
        a: "Our system looks for recognized standards such as USDA Organic, EU Organic, GOTS (for textiles), EcoCert, and Demeter (Biodynamic). We highlight these clearly on every product card."
      },
      {
        q: "Why is location access requested?",
