interface ComparisonModalProps {
    products: Product[];
    onClose: () => void;
    onViewDetails: (product: Product) => void;
}
const ComparisonModal: FC<ComparisonModalProps> = ({ products, onClose, onViewDetails }) => {
    const properties = useMemo(() => ['Purity', 'Price', 'Shipping', 'Vendor', 'Certifications'], []);

    const getPropertyValue = (product: Product, prop: string) => {
        switch(prop) {
            case 'Purity': return `${product.purity}% Organic`;
            case 'Price': return product.price;
            case 'Shipping': return product.shippingPrice;
            case 'Vendor': return product.vendor;
            case 'Certifications': return product.certifications.join(', ');
            default: return '';
        }
    };

    if (products.length === 0) return null;

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50 p-4" onClick={onClose} role="dialog" aria-modal="true" aria-labelledby="compare-modal-title">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
                <div className="sticky top-0 bg-white p-4 border-b flex justify-between items-center z-10">
                    <h2 id="compare-modal-title" className="text-2xl font-bold text-organic-green-dark">Product Comparison</h2>
                    <button onClick={onClose} aria-label="Close comparison" className="text-gray-500 hover:text-gray-800">
                        <XIcon className="w-6 h-6" />
                    </button>
                </div>
                <div className="p-6">
                    <div className="grid gap-6 overflow-x-auto" style={{ gridTemplateColumns: `150px repeat(${products.length}, minmax(200px, 1fr))` }}>
                        {/* Headers */}
                        <div className="font-bold text-gray-600"></div>
                        {products.map(p => (
                            <div key={p.id} className="text-center font-bold text-organic-green-dark text-lg">
                                <h3>{p.name}</h3>
                                <button
                                  onClick={() => onViewDetails(p)}
                                  className="text-sm font-normal text-organic-green underline hover:text-organic-green-dark mt-1"
                                >
                                  View Details
                                </button>
                            </div>
                        ))}

                        {/* Properties */}
                        {properties.map(prop => (
                            <React.Fragment key={prop}>
                                <div className="font-bold text-gray-600 py-3 border-b flex items-center">{prop}</div>
                                {products.map(p => (
                                    <div key={p.id} className="py-3 border-b text-center text-gray-800 flex items-center justify-center">{getPropertyValue(p, prop)}</div>
                                ))}
                            </React.Fragment>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );
};

interface ProductDetailModalProps {
