// --- Chatbot Component ---
interface ChatMessage {
    sender: 'user' | 'bot';
    text: string;
}
interface ChatWidgetProps {
    isChatOpen: boolean;
    setIsChatOpen: (isOpen: boolean) => void;
    chatMessages: ChatMessage[];
    isChatLoading: boolean;
    handleSendMessage: (message: string) => void;
}

const ChatWidget: FC<ChatWidgetProps> = ({ isChatOpen, setIsChatOpen, chatMessages, isChatLoading, handleSendMessage }) => {
    const [input, setInput] = useState('');
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(scrollToBottom, [chatMessages]);

    const onSend = (e: React.FormEvent) => {
        e.preventDefault();
        if (input.trim()) {
            handleSendMessage(input.trim());
            setInput('');
        }
    };

    return (
        <div className="fixed bottom-6 right-6 z-50">
            {/* Chat Window */}
            {isChatOpen && (
                <div className="w-80 h-[28rem] bg-white rounded-lg shadow-2xl flex flex-col transition-all duration-300 overflow-hidden">
                    {/* Header */}
                    <div className="bg-organic-green p-3 flex justify-between items-center text-white">
                        <h3 className="font-bold">Organic Assistant</h3>
                        <button onClick={() => setIsChatOpen(false)} aria-label="Close Chat"><XIcon className="w-5 h-5" /></button>
                    </div>
                    {/* Messages */}
                    <div className="flex-1 p-4 overflow-y-auto bg-gray-50">
                        <div className="flex flex-col space-y-3">
                            {chatMessages.map((msg, index) => (
                                <div key={index} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                                    <div className={`max-w-[85%] p-2 rounded-lg text-sm shadow-sm ${msg.sender === 'user' ? 'bg-organic-green-light text-organic-green-dark rounded-br-none' : 'bg-white text-gray-800 rounded-bl-none border border-gray-100'}`}>
                                        {msg.text}
                                        {isChatLoading && msg.sender === 'bot' && index === chatMessages.length - 1 && !msg.text && (
                                            <span className="flex space-x-1 p-1">
                                                <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce"></span>
                                                <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                                                <span className="w-1.5 h-1.5 bg-gray-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                                            </span>
                                        )}
                                    </div>
                                </div>
                            ))}
                            <div ref={messagesEndRef} />
                        </div>
                    </div>
                    {/* Input */}
                    <form onSubmit={onSend} className="p-2 border-t flex items-center bg-white">
                        <input
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            placeholder="Ask about purity..."
                            className="flex-1 px-3 py-2 border rounded-full focus:outline-none focus:ring-2 focus:ring-organic-green-light text-sm"
                            disabled={isChatLoading}
                        />
                        <button type="submit" disabled={isChatLoading || !input.trim()} className="ml-2 p-2 bg-organic-green text-white rounded-full disabled:bg-gray-400 hover:bg-organic-green-dark transition-colors">
                            <PaperAirplaneIcon className="w-5 h-5" />
                        </button>
                    </form>
                </div>
            )}
            {/* Toggle Button */}
            {!isChatOpen && (
                <button
                    onClick={() => setIsChatOpen(true)}
                    className="bg-organic-green text-white w-16 h-16 rounded-full shadow-lg flex items-center justify-center transform hover:scale-110 transition-transform active:scale-95"
                    aria-label="Open support chat"
                >
                    <ChatBubbleIcon className="w-8 h-8" />
                </button>
            )}
        </div>
    );
};


// --- Main App Component ---
const App: FC = () => {
  const [userLocation, setUserLocation] = useState<UserLocation | null>(null);
  const [searchResults, setSearchResults] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [comparisonList, setComparisonList] = useState<Product[]>([]);
  const [showComparison, setShowComparison] = useState(false);
  const [initialSearchDone, setInitialSearchDone] = useState(false);
  const [detailedProduct, setDetailedProduct] = useState<Product | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Chat state
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([
      { sender: 'bot', text: "Hello! I'm your organic assistant. How can I help you find the perfect product today?" }
  ]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  // SEO title management
  useEffect(() => {
    if (initialSearchDone && searchQuery) {
      document.title = `${searchQuery} - Certified Organic Search Results`;
    } else {
      document.title = "Search for Organics - Discover Certified Organic Products";
    }
  }, [initialSearchDone, searchQuery]);

  const ai = useMemo(() => {
        if (!process.env.API_KEY) return null;
        return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }, []);

  const chat = useMemo(() => {
      if (!ai) return null;
      return ai.chats.create({
          model: 'gemini-2.5-flash',
          config: {
              systemInstruction: "You are a friendly and helpful assistant for 'Search for Organics'. You can answer questions about organic products, certifications, and how to use the site. Be concise and encouraging. Use markdown for formatting.",
          },
      });
  }, [ai]);

  const handleSendMessage = async (message: string) => {
    if (!message.trim() || isChatLoading || !chat) return;

    setIsChatLoading(true);
    setChatMessages(prev => [...prev, { sender: 'user', text: message }, { sender: 'bot', text: '' }]);

    try {
        const result = await chat.sendMessageStream({ message });
        for await (const chunk of result) {
            const chunkText = chunk.text;
            if (chunkText) {
                setChatMessages(prev => {
                    const newMessages = [...prev];
                    const lastMessage = newMessages[newMessages.length - 1];
                    if (lastMessage.sender === 'bot') lastMessage.text += chunkText;
                    return newMessages;
                });
            }
        }
    } catch (err) {
        setChatMessages(prev => {
            const newMessages = [...prev];
            const lastMessage = newMessages[newMessages.length - 1];
            if (lastMessage.sender === 'bot') lastMessage.text = "Sorry, I'm having trouble connecting right now.";
            return newMessages;
        });
    } finally {
        setIsChatLoading(false);
    }
  };

  useEffect(() => {
    navigator.geolocation.getCurrentPosition(
      (position) => setUserLocation({ latitude: position.coords.latitude, longitude: position.coords.longitude }),
      () => setError("Location access denied. Local results will be less accurate.")
    );
  }, []);

  const handleSearch = useCallback(async (query: string) => {
    setIsLoading(true);
    setError(null);
    setInitialSearchDone(true);
    setSearchQuery(query);
    try {
      const results = await searchOrganicProducts(query, userLocation);
      setSearchResults(results);
    } catch (err) {
      setError(err instanceof Error ? err.message : "An unknown error occurred.");
      setSearchResults([]);
    } finally {
      setIsLoading(false);
    }
  }, [userLocation]);

  const handlePromptClick = (prompt: string) => handleSearch(prompt);

  const handleCompareToggle = useCallback((product: Product) => {
    setComparisonList(prev => 
      prev.some(p => p.id === product.id)
        ? prev.filter(p => p.id !== product.id)
        : [...prev, product]
    );
  }, []);

  const handleViewDetails = (product: Product) => setDetailedProduct(product);

  const comparisonIds = useMemo(() => new Set(comparisonList.map(p => p.id)), [comparisonList]);

  // JSON-LD for Search Results
  const resultsSchema = useMemo(() => {
    if (searchResults.length === 0) return null;
    return {
      "@context": "https://schema.org",
      "@type": "ItemList",
      "itemListElement": searchResults.map((p, i) => ({
        "@type": "ListItem",
        "position": i + 1,
        "item": {
          "@type": "Product",
          "name": p.name,
          "description": p.description,
          "brand": { "@type": "Brand", "name": p.vendor },
          "offers": {
            "@type": "Offer",
            "price": p.price.replace(/[^0-9.]/g, ''),
            "priceCurrency": p.price.includes('$') ? 'USD' : 'EUR'
          }
        }
      }))
    };
  }, [searchResults]);

  return (
    <div className="min-h-screen bg-cream text-gray-800 font-sans">
      {resultsSchema && <SchemaMarkup schema={resultsSchema} />}

      <main className="container mx-auto px-4 py-8">
        <header className="text-center mb-12">
          <h1 className="text-5xl font-bold text-organic-green-dark mb-2">Search for Organics</h1>
          <p className="text-lg text-organic-green">Your trusted guide to certified organic products.</p>
        </header>

        <div className="mb-12">
            <SearchBar 
                query={searchQuery} 
                setQuery={setSearchQuery} 
                onSearch={handleSearch} 
                isLoading={isLoading} 
            />
        </div>

        <section aria-live="polite">
            {error && <div className="text-center text-red-600 bg-red-100 p-4 rounded-md mb-8">{error}</div>}

            {isLoading ? (
                <div className="flex flex-col justify-center items-center h-64 space-y-4">
                    <div className="w-16 h-16 border-4 border-organic-green border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-organic-green font-medium animate-pulse">Analyzing purity and prices...</p>
                </div>
            ) : searchResults.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {searchResults.map(product => (
                  <ProductCard 
                    key={product.id} 
                    product={product} 
                    onCompareToggle={handleCompareToggle} 
                    isComparing={comparisonIds.has(product.id)}
                  />
                ))}
              </div>
            ) : initialSearchDone ? (
                <div className="text-center text-gray-500 mt-16">
                    <h3 className="text-2xl font-semibold">No organic results found</h3>
                    <p>Try a more general search term.</p>
                </div>
            ) : (
                <GuideSection onPromptClick={handlePromptClick} />
            )}
        </section>

         <footer className="text-center mt-20 pt-8 border-t border-earth-brown-light pb-10">
            <p className="text-sm text-organic-green mb-4">
                Need help or want to connect? Join our{" "}
                <a href="https://groups.google.com/g/search-for-organics" target="_blank" rel="noopener noreferrer" className="font-semibold underline hover:text-organic-green-dark">community forum</a>
                {" "}or our{" "}
                <a href="https://discord.gg/sQgy7kktS2" target="_blank" rel="noopener noreferrer" className="font-semibold underline hover:text-organic-green-dark">Discord server</a>.
            </p>
            <div className="flex justify-center space-x-6 mb-4 text-xs font-medium text-gray-500 uppercase tracking-widest">
                <a href="#" className="hover:text-organic-green-dark">Privacy Policy</a>
                <a href="#" className="hover:text-organic-green-dark">Terms of Service</a>
                <a href="#" className="hover:text-organic-green-dark">Certifications Guide</a>
            </div>
            <p className="text-xs text-gray-400">© {new Date().getFullYear()} Search for Organics. Powered by Gemini AI. Certified results only.</p>
        </footer>
      </main>

      {/* Comparison Bar */}
      {comparisonList.length > 0 && (
        <div className="sticky bottom-0 bg-white/95 backdrop-blur-md shadow-[0_-4px_20px_rgba(0,0,0,0.1)] p-4 z-40 animate-[slideUp_0.3s_ease-out]">
            <div className="container mx-auto flex justify-between items-center">
                <div className="flex items-center space-x-3">
                    <div className="flex -space-x-2">
                        {comparisonList.slice(0, 3).map(p => (
                            <img key={p.id} src={p.imageUrl} alt="" className="w-8 h-8 rounded-full border-2 border-white object-cover" />
                        ))}
                    </div>
                    <p className="font-semibold text-organic-green-dark">Comparing {comparisonList.length} item{comparisonList.length > 1 ? 's' : ''}</p>
                </div>
                <div className="flex space-x-2">
                    <button 
                        onClick={() => setShowComparison(true)}
                        className="bg-organic-green hover:bg-organic-green-dark text-white font-bold py-2 px-6 rounded-lg transition-all shadow-md active:scale-95"
                    >
                        Compare
                    </button>
                    <button 
                        onClick={() => setComparisonList([])}
                        className="bg-gray-100 hover:bg-gray-200 text-gray-600 font-bold py-2 px-4 rounded-lg transition-colors"
                    >
                        Clear
                    </button>
                </div>
            </div>
        </div>
      )}

      {showComparison && (
        <ComparisonModal 
            products={comparisonList} 
            onClose={() => setShowComparison(false)}
            onViewDetails={handleViewDetails}
        />
      )}

      {detailedProduct && (
        <ProductDetailModal 
            product={detailedProduct}
            onClose={() => setDetailedProduct(null)}
        />
      )}

      <ChatWidget 
        isChatOpen={isChatOpen}
        setIsChatOpen={setIsChatOpen}
        chatMessages={chatMessages}
        isChatLoading={isChatLoading}
        handleSendMessage={handleSendMessage}
      />

      <style>{`
        @keyframes slideUp {
            from { transform: translateY(100%); }
            to { transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

