import { GoogleGenAI, Type } from "@google/genai";
import { Product, UserLocation, SearchResponse, GroundingSource } from '../types';

if (!process.env.API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const nutritionSchema = {
    type: Type.OBJECT,
    description: "Nutritional information, if available. Keys are nutrient names (e.g., 'Calories', 'Protein') and values are strings with amounts and units (e.g., '150 kcal', '20g').",
    properties: {
        Calories: { type: Type.STRING },
        Protein: { type: Type.STRING },
        Fat: { type: Type.STRING },
        Carbohydrates: { type: Type.STRING },
        Sugar: { type: Type.STRING },
        Sodium: { type: Type.STRING },
    },
};

const productSchema = {
  type: Type.OBJECT,
  properties: {
    id: { type: Type.STRING, description: "A unique identifier for the product, like a slug of the name." },
    name: { type: Type.STRING },
    description: { type: Type.STRING },
    purity: { type: Type.NUMBER, description: "Organic purity percentage as a number, e.g., 95 for 95%." },
    certifications: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of organic certifications, e.g., 'USDA Organic'."
    },
    price: { type: Type.STRING, description: "The specific price found in search results, e.g., '$12.99'. Do not use estimates." },
    shippingPrice: { type: Type.STRING, description: "Shipping cost to the user's location, e.g., '$5.99', 'Free', or 'Check Vendor'." },
    vendor: { type: Type.STRING, description: "The store or vendor selling the product." },
    nutrition: nutritionSchema,
  },
  required: ["id", "name", "description", "purity", "certifications", "price", "shippingPrice", "vendor"],
};

export const searchOrganicProducts = async (query: string, location: UserLocation | null): Promise<SearchResponse> => {
  try {
    // Step 1: Grounded search to get up-to-date information
    const groundingPrompt = `
      You are an international search engine for organic products called "Search for Organics".
      Find specific, purchasable certified organic products related to "${query}".

      CRITICAL INSTRUCTIONS:
      1. Prioritize results with the highest organic purity (95%+).
      ${location ? `2. USE THE GOOGLE MAPS TOOL. The user is at [Lat: ${location.latitude}, Lng: ${location.longitude}]. Find vendors nearby and calculate real shipping/delivery status.` : '2. Prioritize well-known vendors with fair pricing.'}
      3. For each product, extract: Precise Name, Description, Purity %, Certifications, Exact Current Price, Shipping, Vendor, and Nutrition.

      List at least 5 products.
    `;

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const tools: any[] = [{ googleSearch: {} }];
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const config: any = { tools };

    if (location) {
        tools.push({ googleMaps: {} });
        config.toolConfig = {
            retrievalConfig: {
                latLng: {
                    latitude: location.latitude,
                    longitude: location.longitude,
                },
            },
        };
    }

    const groundedResult = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: groundingPrompt,
      config: config,
    });

    const groundedText = groundedResult.text;

    // Extract Grounding Sources (Mandatory for Maps/Search tools)
    const sources: GroundingSource[] = [];
    const chunks = groundedResult.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    chunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({
          title: chunk.web.title,
          uri: chunk.web.uri,
          type: 'web'
        });
      }
      if (chunk.maps) {
        sources.push({
          title: chunk.maps.title || "Local Map View",
          uri: chunk.maps.uri,
          type: 'maps'
        });
      }
    });

    // Step 2: Structure the grounded data into JSON
    const structuringPrompt = `
      Analyze the text below. Extract organic product data into a JSON array matching the schema.
      Text:
      ---
      ${groundedText}
      ---
    `;

    const structuredResult = await ai.models.generateContent({
      model: "gemini-2.5-pro",
      contents: structuringPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: productSchema
        }
      }
    });

    const jsonText = structuredResult.text.trim();
    const products: Product[] = JSON.parse(jsonText);

    // Step 3: Add placeholder images
    const productsWithImages = products.map(p => ({
        ...p,
        imageUrl: `https://picsum.photos/seed/${encodeURIComponent(p.name)}/400/300`
    }));

    return {
      products: productsWithImages,
      sources: sources
    };

  } catch (error) {
    console.error("Error searching for organic products:", error);
    throw new Error(error instanceof Error ? error.message : "Search failed.");
  }
};

