// --- Main App Component ---
const App: FC = () => {
  const [userLocation, setUserLocation] = useState<UserLocation | null>(null);
  const [searchResults, setSearchResults] = useState<Product[]>([]);
  const [groundingSources, setGroundingSources] = useState<GroundingSource[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [comparisonList, setComparisonList] = useState<Product[]>([]);
  const [showComparison, setShowComparison] = useState(false);
  const [initialSearchDone, setInitialSearchDone] = useState(false);
  const [detailedProduct, setDetailedProduct] = useState<Product | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatMessages, setChatMessages] = useState<any[]>([{ sender: 'bot', text: "How can I help you find certified organics today?" }]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  const requestLocation = useCallback(() => {
    if (!navigator.geolocation) {
        setError("Geolocation is not supported by your browser.");
        return;
    }
    navigator.geolocation.getCurrentPosition(
      (position) => {
          setUserLocation({ latitude: position.coords.latitude, longitude: position.coords.longitude });
          setError(null);
      },
      (err) => {
          console.warn("Location blocked:", err.message);
          setError("Local search disabled. Allow location access for maps grounding.");
          setUserLocation(null);
      },
      { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
    );
  }, []);

  useEffect(() => {
    requestLocation();
  }, [requestLocation]);

  const handleSearch = useCallback(async (query: string) => {
    setIsLoading(true);
    setError(null);
    setInitialSearchDone(true);
    setSearchQuery(query);
    try {
      const response = await searchOrganicProducts(query, userLocation);
      setSearchResults(response.products);
      setGroundingSources(response.sources);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Search failed.");
      setSearchResults([]);
    } finally {
      setIsLoading(false);
    }
  }, [userLocation]);

  return (
    <div className="min-h-screen bg-cream text-gray-800 font-sans pb-20">
      <main className="container mx-auto px-4 py-8">
        <header className="text-center mb-12">
          <h1 className="text-5xl font-bold text-organic-green-dark mb-2">Search for Organics</h1>
          <p className="text-lg text-organic-green">Verified purity. Local sources. One search.</p>
        </header>

        <div className="mb-12">
            <SearchBar 
                query={searchQuery} 
                setQuery={setSearchQuery} 
                onSearch={handleSearch} 
                isLoading={isLoading} 
                locationActive={!!userLocation}
                onRequestLocation={requestLocation}
            />
        </div>

        <section aria-live="polite">
            {error && <div className="text-center text-amber-700 bg-amber-50 border border-amber-200 p-3 rounded-md mb-8 max-w-xl mx-auto text-sm">{error}</div>}

            {isLoading ? (
                <div className="flex flex-col justify-center items-center h-64 space-y-4">
                    <div className="w-16 h-16 border-4 border-organic-green border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-organic-green font-medium">Verified grounding in progress...</p>
                </div>
            ) : searchResults.length > 0 ? (
              <div className="space-y-12">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {searchResults.map(product => (
                    <ProductCard 
                        key={product.id} 
                        product={product} 
                        onCompareToggle={(p) => setComparisonList(prev => prev.some(x => x.id === p.id) ? prev.filter(x => x.id !== p.id) : [...prev, p])} 
                        isComparing={comparisonList.some(x => x.id === product.id)}
                    />
                    ))}
                </div>

                {/* Grounding Sources - Mandatory Requirement */}
                {groundingSources.length > 0 && (
                    <div className="bg-white rounded-2xl shadow-sm border border-organic-green-light/20 p-8">
                        <h2 className="text-xl font-bold text-organic-green-dark mb-4 flex items-center">
                            <MapLinkIcon className="w-6 h-6 mr-2 text-organic-green" />
                            Verified Sources & Local Maps
                        </h2>
                        <p className="text-sm text-gray-500 mb-6 italic">References and local farm data gathered using Google Search and Maps grounding.</p>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                            {groundingSources.map((source, idx) => (
                                <a 
                                    key={idx} 
                                    href={source.uri} 
                                    target="_blank" 
                                    rel="noopener noreferrer" 
                                    className="flex items-center p-3 bg-cream/50 rounded-lg hover:bg-organic-green-light/10 transition-colors border border-transparent hover:border-organic-green/20"
                                >
                                    <div className={`p-2 rounded-md mr-3 ${source.type === 'maps' ? 'bg-blue-100' : 'bg-green-100'}`}>
                                        {source.type === 'maps' ? <LocationIcon className="w-4 h-4 text-blue-600" /> : <SearchIcon className="w-4 h-4 text-green-600" />}
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className="text-sm font-semibold text-gray-800 truncate">{source.title}</p>
                                        <p className="text-xs text-gray-500 truncate">{new URL(source.uri).hostname}</p>
                                    </div>
                                </a>
                            ))}
                        </div>
                    </div>
                )}
              </div>
            ) : initialSearchDone ? (
                <div className="text-center text-gray-500 mt-16">
                    <h3 className="text-2xl font-semibold">No organic results found</h3>
                </div>
            ) : (
                <GuideSection onPromptClick={handleSearch} />
            )}
        </section>
      </main>

      {comparisonList.length > 0 && (
          <div className="fixed bottom-0 inset-x-0 bg-white shadow-2xl p-4 border-t z-50 flex justify-between items-center max-w-4xl mx-auto rounded-t-xl">
             <div className="font-bold text-organic-green-dark">Comparing {comparisonList.length} products</div>
             <div className="space-x-2">
                <button onClick={() => setComparisonList([])} className="text-sm text-gray-500">Clear All</button>
                <button className="bg-organic-green text-white px-6 py-2 rounded-full font-bold">Launch Comparison</button>
             </div>
          </div>
      )}
    </div>
  );
};

export default App;

