// --- Main App Component ---
const App: FC = () => {
  const [userLocation, setUserLocation] = useState<UserLocation | null>(null);
  const [locationLabel, setLocationLabel] = useState<string>('');
  const [searchResults, setSearchResults] = useState<Product[]>([]);
  const [groundingSources, setGroundingSources] = useState<GroundingSource[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [initialSearchDone, setInitialSearchDone] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showManualLocation, setShowManualLocation] = useState(false);

  const requestLocation = useCallback(() => {
    if (!navigator.geolocation) {
        setError("Geolocation is not supported by your browser.");
        return;
    }

    // Explicitly resetting error to show intent
    setError("Requesting location...");

    navigator.geolocation.getCurrentPosition(
      (position) => {
          setUserLocation({ latitude: position.coords.latitude, longitude: position.coords.longitude });
          setLocationLabel('Auto Location');
          setError(null);
      },
      (err) => {
          console.warn("Location blocked:", err.message);
          let msg = "Location blocked. Enable permissions in browser settings or set manually.";
          if (err.code === 1) msg = "Location denied. Please unlock via browser settings to see local results.";
          if (err.code === 3) msg = "Location timeout. Try manual setting.";
          setError(msg);
          setUserLocation(null);
      },
      { enableHighAccuracy: true, timeout: 8000, maximumAge: 60000 }
    );
  }, []);

  const handleManualLocationSet = (lat: number, lng: number, label: string) => {
      setUserLocation({ latitude: lat, longitude: lng });
      setLocationLabel(label);
      setShowManualLocation(false);
      setError(null);
  };

  useEffect(() => {
    requestLocation();
  }, [requestLocation]);

  const handleSearch = useCallback(async (query: string) => {
    if (!query.trim()) return;
    setIsLoading(true);
    setError(null);
    setInitialSearchDone(true);
    setSearchQuery(query);
    try {
      const response = await searchOrganicProducts(query, userLocation);
      setSearchResults(response.products);
      setGroundingSources(response.sources);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Search failed.");
      setSearchResults([]);
    } finally {
      setIsLoading(false);
    }
  }, [userLocation]);

  return (
    <div className="min-h-screen bg-cream text-gray-800 font-sans selection:bg-organic-green/20">
      <main className="container mx-auto px-4 py-12 max-w-6xl">
        <header className="text-center mb-16 space-y-4">
          <h1 className="text-6xl font-black text-organic-green-dark tracking-tight">Search for Organics</h1>
          <p className="text-xl text-organic-green font-medium max-w-xl mx-auto">International directory for verified purity and sustainable local discovery.</p>
        </header>

        <div className="mb-16">
            <SearchBar 
                query={searchQuery} 
                setQuery={setSearchQuery} 
                onSearch={handleSearch} 
                isLoading={isLoading} 
                locationActive={!!userLocation}
                onRequestLocation={requestLocation}
                onManualLocation={() => setShowManualLocation(true)}
                locationLabel={locationLabel}
            />
        </div>

        <section aria-live="polite">
            {error && (
                <div className="text-center mb-10 animate-pulse">
                    <div className="inline-flex items-center text-amber-800 bg-amber-50 border border-amber-200 px-4 py-2 rounded-full text-sm font-medium">
                        <span className="w-2 h-2 bg-amber-500 rounded-full mr-2"></span>
                        {error}
                    </div>
                </div>
            )}

            {isLoading ? (
                <div className="flex flex-col justify-center items-center h-80 space-y-6">
                    <div className="relative">
                        <div className="w-20 h-20 border-[6px] border-organic-green-light border-t-organic-green rounded-full animate-spin"></div>
                        <div className="absolute inset-0 flex items-center justify-center">
                            <SearchIcon className="w-8 h-8 text-organic-green animate-pulse" />
                        </div>
                    </div>
                    <div className="text-center space-y-2">
                        <p className="text-xl font-bold text-organic-green-dark">Grounding Organic Sources...</p>
                        <p className="text-sm text-gray-500">Scanning local maps and certification databases</p>
                    </div>
                </div>
            ) : searchResults.length > 0 ? (
              <div className="space-y-20">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
                    {searchResults.map(product => (
                      <ProductCard key={product.id} product={product} />
                    ))}
                </div>

                {groundingSources.length > 0 && (
                    <div className="bg-white rounded-[2.5rem] shadow-xl shadow-organic-green/5 border border-organic-green-light/10 p-10">
                        <div className="flex flex-col md:flex-row md:items-end justify-between mb-8 gap-4">
                            <div className="space-y-1">
                                <h2 className="text-2xl font-black text-organic-green-dark flex items-center">
                                    <MapLinkIcon className="w-7 h-7 mr-2.5 text-organic-green" />
                                    Verified Evidence & Maps
                                </h2>
                                <p className="text-gray-500 font-medium italic">Transparency index: Real-time citations found via Search & Maps grounding.</p>
                            </div>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                            {groundingSources.map((source, idx) => (
                                <a 
                                    key={idx} 
