                                    className="flex items-center p-4 bg-cream/30 rounded-2xl hover:bg-white hover:shadow-lg transition-all border border-transparent hover:border-organic-green/10 group"
                                >
                                    <div className={`p-3 rounded-xl mr-4 shrink-0 transition-colors ${source.type === 'maps' ? 'bg-blue-100 group-hover:bg-blue-200' : 'bg-green-100 group-hover:bg-green-200'}`}>
