  const [searchQuery, setSearchQuery] = useState('');
  const [showManualLocation, setShowManualLocation] = useState(false);

  const requestLocation = useCallback(() => {
    if (!navigator.geolocation) {
        setLocationError("Browser doesn't support geolocation.");
        return;
    }

    setLocationError("Awaiting permission...");

    navigator.geolocation.getCurrentPosition(
      (position) => {
          setUserLocation({ latitude: position.coords.latitude, longitude: position.coords.longitude });
          setLocationLabel('Current Location');
          setLocationError(null);
      },
      (err) => {
          console.warn("Location error:", err.message);
          let msg = "Location Access Blocked";
          if (err.code === 1) msg = "Permission Denied by User";
          if (err.code === 2) msg = "Position Unavailable";
          if (err.code === 3) msg = "Location Request Timed Out";
          setLocationError(msg);
          setUserLocation(null);
      },
      { enableHighAccuracy: false, timeout: 10000, maximumAge: 0 }
    );
  }, []);

  const handleManualLocationSet = (lat: number, lng: number, label: string) => {
      setUserLocation({ latitude: lat, longitude: lng });
      setLocationLabel(label);
      setShowManualLocation(false);
      setLocationError(null);
  };

  const handleSearch = useCallback(async (query: string) => {
    if (!query.trim()) return;
    setIsLoading(true);
    setError(null);
    setInitialSearchDone(true);
    setSearchQuery(query);
    try {
      const response = await searchOrganicProducts(query, userLocation);
      setSearchResults(response.products);
      setGroundingSources(response.sources);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Search failed.");
      setSearchResults([]);
    } finally {
      setIsLoading(false);
