  onSearch, 
  isLoading, 
  query, 
  setQuery, 
  locationActive, 
  onRequestLocation, 
  onManualLocation,
  locationLabel,
  locationError
}) => {
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim() && !isLoading) {
      onSearch(query.trim());
