                <LocationIcon className="w-4 h-4 mr-2" />
                {locationActive ? (locationLabel || 'Location Active') : 'Local Search Disabled'}
            </div>

            <div className="flex items-center space-x-3 bg-white/50 p-1 rounded-xl border border-gray-100 shadow-sm">
                <button 
                    onClick={(e) => { e.preventDefault(); onRequestLocation(); }}
                    className={`text-xs font-black px-4 py-2 rounded-lg transition-all shadow-sm active:scale-95 ${locationActive ? 'text-organic-green-dark hover:bg-organic-green/5' : 'text-white bg-organic-green hover:bg-organic-green-dark'}`}
                >
                    {locationActive ? 'Update GPS' : 'Enable Local Search'}
                </button>
                <span className="text-gray-300">|</span>
                <button 
                    onClick={onManualLocation}
                    className="text-xs font-bold text-gray-600 hover:text-organic-green px-3 py-2 rounded-lg transition-colors"
                >
                    {locationActive ? 'Change City' : 'Set Manually'}
