            </div>
         </div>
         {locationError && !locationActive && (
             <div className="flex flex-col items-center gap-1">
                <div className="flex items-center gap-2 text-[10px] font-black text-red-600 uppercase tracking-widest bg-red-50 px-3 py-1.5 rounded border border-red-100">
