const App: FC = () => {
  const [userLocation, setUserLocation] = useState<UserLocation | null>(null);
  const [locationLabel, setLocationLabel] = useState<string>('');
  const [locationStatus, setLocationStatus] = useState<'idle' | 'locating' | 'error' | 'success'>('idle');
  const [locationErrorMsg, setLocationErrorMsg] = useState<string | null>(null);

  const [searchResults, setSearchResults] = useState<Product[]>([]);
  const [groundingSources, setGroundingSources] = useState<GroundingSource[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [initialSearchDone, setInitialSearchDone] = useState(false);
  const [globalError, setGlobalError] = useState<string | null>(null);
  const [showManualLocation, setShowManualLocation] = useState(false);

  const requestLocation = useCallback(() => {
    if (!navigator.geolocation) {
        setLocationErrorMsg("Geolocation is not supported by your browser.");
        setLocationStatus('error');
        return;
    }

    setLocationStatus('locating');
    setLocationErrorMsg(null);

    const options = {
        enableHighAccuracy: true,
        timeout: 8000,
        maximumAge: 0
    };

    navigator.geolocation.getCurrentPosition(
        (pos) => {
            setUserLocation({ latitude: pos.coords.latitude, longitude: pos.coords.longitude });
            setLocationLabel('GPS Verified');
            setLocationStatus('success');
            setLocationErrorMsg(null);
        },
        (err) => {
            console.warn("Location acquisition failed:", err);
            let msg = "Location Access Denied";
            if (err.code === 2) msg = "Location Position Unavailable";
            if (err.code === 3) msg = "Location Request Timeout";

            setLocationErrorMsg(msg);
            setLocationStatus('error');
            setUserLocation(null);
        },
        options
    );
  }, []);

  // Try once on mount
  useEffect(() => {
    requestLocation();
  }, [requestLocation]);

  const handleManualLocationSet = (lat: number, lng: number, label: string) => {
      setUserLocation({ latitude: lat, longitude: lng });
      setLocationLabel(label);
      setShowManualLocation(false);
      setLocationStatus('success');
      setLocationErrorMsg(null);
  };

  const handleSearch = useCallback(async (query: string) => {
    if (!query.trim()) return;
    setIsLoading(true);
    setGlobalError(null);
    setInitialSearchDone(true);
    setSearchQuery(query);
    try {
      const response = await searchOrganicProducts(query, userLocation);
      setSearchResults(response.products);
      setGroundingSources(response.sources);
    } catch (err) {
      setGlobalError(err instanceof Error ? err.message : "Search failed.");
      setSearchResults([]);
    } finally {
      setIsLoading(false);
    }
  }, [userLocation]);

  return (
    <div className="min-h-screen bg-cream text-gray-800 font-sans selection:bg-organic-green/20 pb-20">
      <main className="container mx-auto px-4 py-12 max-w-6xl">
        <header className="text-center mb-16 space-y-4">
          <h1 className="text-5xl md:text-7xl font-black text-organic-green-dark tracking-tighter">Search for Organics</h1>
          <p className="text-xl text-organic-green font-medium max-w-xl mx-auto">Hyper-Local Discovery. Globally Verified Purity.</p>
        </header>

        <div className="mb-16">
            <SearchBar 
                query={searchQuery} 
                setQuery={setSearchQuery} 
                onSearch={handleSearch} 
                isLoading={isLoading} 
                locationActive={!!userLocation}
                onRequestLocation={requestLocation}
                onManualLocation={() => setShowManualLocation(true)}
                locationLabel={locationLabel}
                locationStatus={locationStatus}
                locationErrorMsg={locationErrorMsg}
            />
        </div>

        <section aria-live="polite">
            {globalError && (
                <div className="text-center mb-10">
                    <div className="inline-flex items-center text-red-800 bg-red-50 border border-red-200 px-6 py-3 rounded-2xl text-sm font-bold shadow-sm">
                        {globalError}
                    </div>
                </div>
            )}

            {isLoading ? (
                <div className="flex flex-col justify-center items-center h-80 space-y-6">
                    <div className="relative">
                        <div className="w-20 h-20 border-[6px] border-organic-green-light border-t-organic-green rounded-full animate-spin"></div>
                    </div>
                    <div className="text-center space-y-2">
                        <p className="text-xl font-black text-organic-green-dark">Analyzing Local Purity...</p>
                        <p className="text-sm text-gray-500 font-medium italic">Grounding search results with real-time certification data.</p>
                    </div>
                </div>
            ) : searchResults.length > 0 ? (
              <div className="space-y-20">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
                    {searchResults.map(product => (
                      <ProductCard key={product.id} product={product} />
                    ))}
                </div>

                {groundingSources.length > 0 && (
                    <div className="bg-white rounded-[2.5rem] shadow-xl shadow-organic-green/5 border border-organic-green-light/10 p-10">
                        <div className="flex flex-col md:flex-row md:items-end justify-between mb-8 gap-4">
                            <div className="space-y-1">
                                <h2 className="text-2xl font-black text-organic-green-dark flex items-center">
                                    <MapLinkIcon className="w-7 h-7 mr-2.5 text-organic-green" />
                                    Transparency Index
                                </h2>
                                <p className="text-gray-500 font-medium italic">Verified source references used to ground these results.</p>
                            </div>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                            {groundingSources.map((source, idx) => (
                                <a 
                                    key={idx} 
                                    href={source.uri} 
                                    target="_blank" 
                                    rel="noopener noreferrer" 
                                    className="flex items-center p-4 bg-cream/30 rounded-2xl hover:bg-white hover:shadow-lg transition-all border border-transparent hover:border-organic-green/10 group"
                                >
                                    <div className={`p-3 rounded-xl mr-4 shrink-0 transition-colors ${source.type === 'maps' ? 'bg-blue-100 group-hover:bg-blue-200' : 'bg-green-100 group-hover:bg-green-200'}`}>
                                        {source.type === 'maps' ? <LocationIcon className="w-5 h-5 text-blue-600" /> : <SearchIcon className="w-5 h-5 text-green-600" />}
                                    </div>
                                    <div className="min-w-0">
                                        <p className="text-sm font-bold text-gray-800 truncate leading-tight mb-0.5">{source.title}</p>
                                        <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest truncate">{new URL(source.uri).hostname}</p>
                                    </div>
                                </a>
                            ))}
                        </div>
                    </div>
                )}
              </div>
            ) : initialSearchDone ? (
                <div className="text-center py-24 space-y-4">
                    <div className="text-6xl mb-4">🍃</div>
                    <h3 className="text-2xl font-black text-organic-green-dark">No Local Organic Matches</h3>
                    <p className="text-gray-500 max-w-md mx-auto">We couldn't find specific organic matches for that query in your area. Try a broader term like "fruit" or "market".</p>
                </div>
            ) : (
                <div className="max-w-4xl mx-auto mt-20 space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-1000">
                    <div className="text-center space-y-4">
                        <h2 className="text-3xl font-bold text-organic-green-dark">Search locally for the best quality</h2>
