import { GoogleGenAI, Type } from "@google/genai";
import { Product, UserLocation, SearchResponse, GroundingSource } from '../types';

if (!process.env.API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const nutritionSchema = {
    type: Type.OBJECT,
    description: "Nutritional information, if available. Keys are nutrient names (e.g., 'Calories', 'Protein') and values are strings with amounts and units (e.g., '150 kcal', '20g').",
    properties: {
        Calories: { type: Type.STRING },
        Protein: { type: Type.STRING },
        Fat: { type: Type.STRING },
        Carbohydrates: { type: Type.STRING },
        Sugar: { type: Type.STRING },
        Sodium: { type: Type.STRING },
    },
};

const productSchema = {
  type: Type.OBJECT,
  properties: {
    id: { type: Type.STRING, description: "A unique identifier for the product, like a slug of the name." },
    name: { type: Type.STRING },
    description: { type: Type.STRING },
    purity: { type: Type.NUMBER, description: "Organic purity percentage as a number, e.g., 95 for 95%." },
    certifications: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of organic certifications, e.g., 'USDA Organic', 'EU Organic', 'GOTS'."
    },
    price: { type: Type.STRING, description: "The specific price found in search results, e.g., '$12.99'." },
    shippingPrice: { type: Type.STRING, description: "Shipping cost or 'In-store only', e.g., '$5.99', 'Free', or 'Local Pickup'." },
    vendor: { type: Type.STRING, description: "The store, farm, or vendor name." },
    isLocal: { type: Type.BOOLEAN, description: "True if the vendor is a physical store or farm located near the user's provided coordinates." },
    nutrition: nutritionSchema,
  },
  required: ["id", "name", "description", "purity", "certifications", "price", "shippingPrice", "vendor", "isLocal"],
};

export const searchOrganicProducts = async (query: string, location: UserLocation | null): Promise<SearchResponse> => {
  try {
    // Step 1: Grounded search to get up-to-date local and web information
    const groundingPrompt = `
      You are "Search for Organics", an AI search engine specializing in local and global organic goods.
      Query: "${query}"

      CRITICAL INSTRUCTIONS:
      1. Find certified organic products (USDA, EU, Soil Association, etc.).
      2. Purity analysis: Report the purity % based on ingredients and certification labels.
      ${location ? `3. HYPER-LOCAL SEARCH: The user is at [Latitude: ${location.latitude}, Longitude: ${location.longitude}]. USE GOOGLE MAPS to find organic farms, health food stores, and specialized grocers NEAR THIS LOCATION first. Tag these results as local.` : '3. Search for major online organic retailers and global brands.'}
      4. Include precise pricing and availability (In-store pickup vs online shipping).

      Extract at least 6 diverse products or sources.
    `;

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const tools: any[] = [{ googleSearch: {} }];
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const config: any = { 
      tools,
      model: "gemini-2.5-flash-native-audio-preview-12-2025" 
    };

    if (location) {
        tools.push({ googleMaps: {} });
        config.toolConfig = {
            retrievalConfig: {
                latLng: {
                    latitude: location.latitude,
                    longitude: location.longitude,
                },
            },
        };
    }

    const groundedResult = await ai.models.generateContent({
      model: config.model,
      contents: groundingPrompt,
      config: config,
    });

    const groundedText = groundedResult.text;

    // Extract Grounding Sources
    const sources: GroundingSource[] = [];
    const chunks = groundedResult.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    chunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({
          title: chunk.web.title,
          uri: chunk.web.uri,
          type: 'web'
        });
      }
      if (chunk.maps) {
        sources.push({
          title: chunk.maps.title || "Local Map View",
          uri: chunk.maps.uri,
          type: 'maps'
        });
      }
    });

    // Step 2: Structure the grounded data into JSON using a high-quality model
    const structuringPrompt = `
      Extract product data from the organic search results text below. 
      Create a JSON array. Mark products as 'isLocal: true' if the text indicates they are physical stores or farms near the user's location.
      Text:
      ---
      ${groundedText}
      ---
    `;

    const structuredResult = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: structuringPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: productSchema
        }
      }
    });

    const jsonText = structuredResult.text.trim();
    const products: Product[] = JSON.parse(jsonText);

    // Step 3: Add placeholder images based on product names
    const productsWithImages = products.map(p => ({
        ...p,
        imageUrl: `https://picsum.photos/seed/organic-${encodeURIComponent(p.name.substring(0, 10))}/400/300`
    }));

    return {
      products: productsWithImages,
      sources: sources
    };

  } catch (error) {
    console.error("Error in organic search pipeline:", error);
    throw new Error(error instanceof Error ? error.message : "Search failed.");
  }
};

