const App: FC = () => {
  const [userLocation, setUserLocation] = useState<UserLocation | null>(null);
  const [locationLabel, setLocationLabel] = useState<string>('');
  const [locationStatus, setLocationStatus] = useState<'idle' | 'locating' | 'error' | 'success'>('idle');
  const [locationErrorMsg, setLocationErrorMsg] = useState<string | null>(null);

  const [searchResults, setSearchResults] = useState<Product[]>([]);
  const [groundingSources, setGroundingSources] = useState<GroundingSource[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [initialSearchDone, setInitialSearchDone] = useState(false);
  const [globalError, setGlobalError] = useState<string | null>(null);
  const [showManualLocation, setShowManualLocation] = useState(false);

  const requestLocation = useCallback(() => {
    if (!navigator.geolocation) {
        setLocationErrorMsg("GPS Unsupported");
        setLocationStatus('error');
        return;
    }

    setLocationStatus('locating');
    setLocationErrorMsg(null);

    const options = {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0
    };

    navigator.geolocation.getCurrentPosition(
        (pos) => {
            setUserLocation({ latitude: pos.coords.latitude, longitude: pos.coords.longitude });
            setLocationLabel('Nearby Search Active');
            setLocationStatus('success');
            setLocationErrorMsg(null);
        },
        (err) => {
            console.warn("Location error:", err);
            let msg = "Location Access Denied";
            if (err.code === 2) msg = "GPS Signal Lost";
            if (err.code === 3) msg = "GPS Request Timeout";

            setLocationErrorMsg(msg);
            setLocationStatus('error');
            setUserLocation(null);
        },
        options
    );
  }, []);

  useEffect(() => {
    // Try auto-location once on mount
    requestLocation();
  }, [requestLocation]);

  const handleManualLocationSet = (lat: number, lng: number, label: string) => {
      setUserLocation({ latitude: lat, longitude: lng });
      setLocationLabel(label);
      setShowManualLocation(false);
      setLocationStatus('success');
      setLocationErrorMsg(null);
  };

  const handleSearch = useCallback(async (query: string) => {
    if (!query.trim()) return;
    setIsLoading(true);
    setGlobalError(null);
    setInitialSearchDone(true);
    setSearchQuery(query);
    try {
      const response = await searchOrganicProducts(query, userLocation);
      setSearchResults(response.products);
      setGroundingSources(response.sources);
    } catch (err) {
      setGlobalError(err instanceof Error ? err.message : "Search failed.");
      setSearchResults([]);
    } finally {
      setIsLoading(false);
    }
  }, [userLocation]);

  return (
    <div className="min-h-screen bg-cream text-gray-800 font-sans selection:bg-organic-green/20 pb-20">
      <main className="container mx-auto px-4 py-12 max-w-6xl">
        <header className="text-center mb-16 space-y-4 animate-in fade-in slide-in-from-top-4 duration-700">
          <div className="inline-block p-3 rounded-2xl bg-organic-green/10 mb-2">
            <span className="text-3xl">🌿</span>
          </div>
          <h1 className="text-5xl md:text-7xl font-black text-organic-green-dark tracking-tighter">Search for Organics</h1>
          <p className="text-xl text-organic-green font-medium max-w-xl mx-auto">Verified Certification. Locally Grounded Results.</p>
        </header>

        <div className="mb-16">
            <SearchBar 
                query={searchQuery} 
                setQuery={setSearchQuery} 
                onSearch={handleSearch} 
                isLoading={isLoading} 
                locationActive={!!userLocation}
                onRequestLocation={requestLocation}
                onManualLocation={() => setShowManualLocation(true)}
                locationLabel={locationLabel}
                locationStatus={locationStatus}
                locationErrorMsg={locationErrorMsg}
            />
        </div>

        <section aria-live="polite">
            {globalError && (
                <div className="text-center mb-10">
                    <div className="inline-flex items-center text-red-800 bg-red-50 border border-red-200 px-6 py-3 rounded-2xl text-sm font-bold shadow-sm">
                        {globalError}
                    </div>
                </div>
            )}

            {isLoading ? (
                <div className="flex flex-col justify-center items-center h-80 space-y-6">
                    <div className="relative">
                        <div className="w-20 h-20 border-[6px] border-organic-green-light border-t-organic-green rounded-full animate-spin"></div>
                    </div>
                    <div className="text-center space-y-2">
                        <p className="text-xl font-black text-organic-green-dark">Analyzing Local Purity...</p>
                        <p className="text-sm text-gray-500 font-medium italic">Grounding search results with real-time certification data.</p>
                    </div>
                </div>
            ) : searchResults.length > 0 ? (
              <div className="space-y-20 animate-in fade-in duration-700">
                <div className="flex items-center justify-between border-b border-gray-100 pb-6">
                    <h2 className="text-2xl font-black text-organic-green-dark">Top Certified Matches</h2>
                    <div className="flex gap-2">
                         {userLocation ? (
                             <span className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full border border-blue-100">Nearby Results Enabled</span>
                         ) : (
                             <button onClick={() => setShowManualLocation(true)} className="text-xs font-bold text-gray-400 bg-gray-50 px-3 py-1.5 rounded-full border border-gray-100 hover:bg-gray-100 transition-colors">Set Location for Nearby Deals</button>
                         )}
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
                    {searchResults.map(product => (
                      <ProductCard key={product.id} product={product} />
                    ))}
                </div>

                {groundingSources.length > 0 && (
                    <div className="bg-white rounded-[2.5rem] shadow-xl shadow-organic-green/5 border border-organic-green-light/10 p-10">
