// --- UI Components ---
interface SearchBarProps {
  onSearch: (query: string) => void;
  isLoading: boolean;
  query: string;
  setQuery: (q: string) => void;
  locationActive: boolean;
  onRequestLocation: () => void;
  onManualLocation: () => void;
  locationLabel?: string;
  locationStatus?: 'idle' | 'locating' | 'error' | 'success';
  locationErrorMsg?: string | null;
}

const SearchBar: FC<SearchBarProps> = ({ 
  onSearch, 
  isLoading, 
  query, 
  setQuery, 
  locationActive, 
  onRequestLocation, 
  onManualLocation,
  locationLabel,
  locationStatus,
  locationErrorMsg
}) => {
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim() && !isLoading) {
      onSearch(query.trim());
    }
  };

  return (
    <div className="w-full max-w-2xl mx-auto space-y-4">
      <div className="flex flex-col items-center gap-3">
         <div className="flex flex-wrap justify-center items-center gap-2">
            <button 
                onClick={onRequestLocation}
                disabled={locationStatus === 'locating'}
                className={`inline-flex items-center px-4 py-2 rounded-full text-xs font-black transition-all border shadow-sm active:scale-95 ${locationActive ? 'bg-green-100 text-green-700 border-green-200' : 'bg-white text-gray-400 border-gray-100 hover:border-organic-green hover:text-organic-green'} ${locationStatus === 'locating' ? 'opacity-70 cursor-wait' : ''}`}
            >
                <LocationIcon className={`w-4 h-4 mr-2 ${locationStatus === 'locating' ? 'animate-bounce' : ''}`} />
                {locationStatus === 'locating' ? 'Locating...' : (locationActive ? (locationLabel || 'GPS Verified') : 'Enable Nearby Discovery')}
            </button>

            <button 
                onClick={onManualLocation}
                className="inline-flex items-center px-4 py-2 rounded-full text-xs font-black bg-white text-gray-500 border border-gray-100 hover:border-organic-green hover:text-organic-green transition-all shadow-sm"
            >
                {locationActive ? 'Change Area' : 'Manual City'}
            </button>
         </div>

         {locationErrorMsg && !locationActive && (
             <div className="flex items-center gap-2 text-[10px] font-black text-amber-700 uppercase tracking-widest bg-amber-50 px-4 py-2 rounded-lg border border-amber-200 animate-in fade-in duration-300">
                <XIcon className="w-3.5 h-3.5" />
                {locationErrorMsg}
                <button onClick={onRequestLocation} className="ml-2 underline font-black text-amber-900">Try Again</button>
             </div>
         )}
      </div>

      <form onSubmit={handleSubmit} role="search" className="relative group">
        <label htmlFor="organic-search-input" className="sr-only">Search for organic products</label>
        <input
          id="organic-search-input"
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder={locationActive ? "Search local farms, milk, markets..." : "Search organic brands & global items..."}
          className="w-full pl-6 pr-14 py-4 border-2 border-organic-green-light focus:border-organic-green-dark focus:ring-organic-green-dark rounded-full shadow-lg transition-all duration-300 text-lg placeholder:text-gray-300 bg-white"
          disabled={isLoading}
          aria-busy={isLoading}
        />
        <button
          type="submit"
          disabled={isLoading}
          aria-label="Submit Search"
          className="absolute inset-y-0 right-0 flex items-center justify-center w-16 h-full text-white bg-organic-green hover:bg-organic-green-dark rounded-r-full disabled:bg-gray-400 shadow-md group-focus-within:scale-105 transition-transform"
        >
          {isLoading ? (
            <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
          ) : (
            <SearchIcon className="w-7 h-7" />
          )}
        </button>
      </form>
    </div>
  );
};

