interface SearchBarProps {
  onSearch: (query: string) => void;
  isLoading: boolean;
  query: string;
  setQuery: (q: string) => void;
  locationActive: boolean;
  onRequestLocation: () => void;
  onManualLocation: () => void;
  locationLabel?: string;
  locationStatus?: 'idle' | 'locating' | 'error' | 'success';
  locationErrorMsg?: string | null;
}

const SearchBar: FC<SearchBarProps> = ({ 
  onSearch, 
  isLoading, 
  query, 
  setQuery, 
  locationActive, 
  onRequestLocation, 
  onManualLocation,
  locationLabel,
  locationStatus,
  locationErrorMsg
}) => {
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim() && !isLoading) {
      onSearch(query.trim());
    }
  };

  return (
    <div className="w-full max-w-2xl mx-auto space-y-5">
      <div className="flex flex-col items-center gap-3">
         <div className="flex flex-wrap justify-center items-center gap-3">
            <button 
                onClick={onRequestLocation}
                disabled={locationStatus === 'locating'}
                className={`group flex items-center px-4 py-2.5 rounded-2xl text-xs font-black transition-all border shadow-sm active:scale-95 ${locationActive ? 'bg-green-50 text-green-700 border-green-200' : 'bg-white text-gray-500 border-gray-100 hover:border-organic-green hover:text-organic-green'} ${locationStatus === 'locating' ? 'opacity-70 cursor-wait' : ''}`}
                title="Use current GPS location"
            >
                <LocationIcon className={`w-4 h-4 mr-2 ${locationStatus === 'locating' ? 'animate-bounce text-organic-green' : 'group-hover:text-organic-green transition-colors'}`} />
                {locationStatus === 'locating' ? 'Locating...' : (locationActive ? (locationLabel || 'GPS Verified') : 'Find Nearby Organics')}
            </button>

            <button 
                onClick={onManualLocation}
                className="flex items-center px-4 py-2.5 rounded-2xl text-xs font-black bg-white text-gray-400 border border-gray-100 hover:border-organic-green hover:text-organic-green transition-all shadow-sm group"
                title="Select a specific city"
            >
                <GlobeIcon className="w-4 h-4 mr-2 group-hover:text-organic-green transition-colors" />
                {locationActive ? 'Change City' : 'Set Manual City'}
            </button>
         </div>

         {locationErrorMsg && !locationActive && (
             <div className="flex items-center gap-2 text-[10px] font-black text-amber-700 uppercase tracking-widest bg-amber-50 px-4 py-2.5 rounded-xl border border-amber-200 animate-in slide-in-from-top-2 duration-300">
                <XIcon className="w-3.5 h-3.5" />
                <span>{locationErrorMsg}</span>
                <button onClick={onRequestLocation} className="ml-2 px-2 py-0.5 bg-amber-100 rounded-lg hover:bg-amber-200 transition-colors underline font-black text-amber-900">Retry GPS</button>
             </div>
         )}
      </div>

      <form onSubmit={handleSubmit} role="search" className="relative">
        <label htmlFor="organic-search-input" className="sr-only">Search for organic products</label>
        <input
          id="organic-search-input"
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder={locationActive ? "Organic honey, farms, milk near you..." : "Organic brands, products, groceries..."}
          className="w-full pl-7 pr-16 py-4.5 border-2 border-organic-green-light/40 focus:border-organic-green-dark focus:ring-4 focus:ring-organic-green/5 rounded-3xl shadow-xl transition-all duration-300 text-lg placeholder:text-gray-300 bg-white"
          disabled={isLoading}
          aria-busy={isLoading}
        />
        <button
          type="submit"
          disabled={isLoading}
          aria-label="Submit Search"
          className="absolute inset-y-1.5 right-1.5 flex items-center justify-center w-14 text-white bg-organic-green hover:bg-organic-green-dark rounded-2xl disabled:bg-gray-300 shadow-md transition-all active:scale-95"
        >
          {isLoading ? (
            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
          ) : (
            <SearchIcon className="w-6 h-6" />
          )}
        </button>
      </form>
    </div>
  );
};

